import React, { useEffect, useState } from 'react';
import FavoriteBorderRoundedIcon from '@mui/icons-material/FavoriteBorderRounded';
import FavoriteRoundedIcon from '@mui/icons-material/FavoriteRounded';
import 'swiper/css'
import 'swiper/css/effect-coverflow'
import 'swiper/css/navigation'
import { EffectCoverflow, Navigation } from 'swiper/modules';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Box, Button, Grid, Modal, ToggleButton, ToggleButtonGroup, Typography, Stack, Divider, IconButton } from '@mui/material';
import { Helmet } from 'react-helmet-async';
import GoodsItem from './GoodsItem';

const Item = (props) => {
    const { item, setOrder, setWishList, wishList, allProducts } = props;

    const [isphotoOpen, setphotoOpen] = useState(false);
    const [CurrentPhoto, setCurrentPhoto] = useState("");
    const [alignmentSize, setAlignmentSize] = useState(item.sizes[0]);
    const [alignmentColor, setAlignmentColor] = useState(item.colors[0]);

    const openThePhoto = (currentPhotoSRC) => {
        setCurrentPhoto(currentPhotoSRC);
        setphotoOpen(true);
    };

    const isInWishList = wishList.some(itemInWish => itemInWish.id === item.id);

    const similarGoods = () => {
        let arr = allProducts.filter((good) => good.category.includes(item.category) && good.id !== item.id);
        arr = arr.slice(0, 3);
        if (arr.length) {
            return (
                <Box sx={{ mt: 10 }}>
                    <Typography 
                        variant="h4" 
                        sx={{ 
                            mb: 4, 
                            fontWeight: 800, 
                            textTransform: 'uppercase', 
                            letterSpacing: '0.05em' 
                        }}
                    >
                        Complete the <Box component="span" sx={{ color: 'primary.main' }}>Look</Box>
                    </Typography>
                    <Grid container spacing={4}>
                        {arr.map((similarItem) => (
                            <GoodsItem key={similarItem.id} id={similarItem.id} setWishList={setWishList} wishList={wishList} {...similarItem} />
                        ))}
                    </Grid>
                </Box>
            )
        }
    }

    const putPropertyAndValue = (property, value) => (
        <Box key={property} sx={{ mb: 2 }}>
            <Stack direction="row" justifyContent="space-between" alignItems="center">
                <Typography variant="body2" sx={{ color: 'text.secondary', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                    {property}
                </Typography>
                <Typography variant="body1" sx={{ fontWeight: 500 }}>
                    {value}
                </Typography>
            </Stack>
            <Divider sx={{ mt: 1.5, opacity: 0.1 }} />
        </Box>
    );

    const handleAlignmentSize = (event, newAlignment) => {
        if (newAlignment !== null) setAlignmentSize(newAlignment);
    };
    
    const handleAlignmentColor = (event, newAlignment) => {
        if (newAlignment !== null) setAlignmentColor(newAlignment);
    };

    const UAvalue = (item.category === 'hoodies' ? "Худі" : item.category === "T-shirts" ?
        "Футболки" : item.category === "suits" ? 'Костюми' : item.category === "trousers" ? 'Штани' : '');

    return (
        <Box sx={{ pt: 4 }}>
            <Helmet>
                <title>{`${item.name} | Wear & Enjoy`}</title>
                <meta name="description" content={item.description} />
                <link rel="canonical" href={"/" + item.id} />
            </Helmet>

            <Grid container spacing={8}>
                <Grid item xs={12} md={7}>
                    <Swiper
                        style={{
                            "--swiper-navigation-color": "#D4AF37",
                            "--swiper-pagination-color": "#D4AF37",
                        }}
                        effect={'coverflow'}
                        grabCursor={true}
                        centeredSlides={true}
                        slidesPerView={'auto'}
                        coverflowEffect={{
                            rotate: 0,
                            stretch: 5,
                            depth: 10,
                            modifier: 12,
                        }}
                        navigation={{
                            nextEl: '.swiper-button-next',
                            prevEl: '.swiper-button-prev',
                        }}
                        modules={[EffectCoverflow, Navigation]}
                    >
                        {item.photos.map((photo, i) => (
                            <SwiperSlide
                                onClick={() => openThePhoto(photo)}
                                key={photo} 
                                style={{ width: 'auto' }}
                            >
                                <Box sx={{ 
                                    borderRadius: '24px', 
                                    overflow: 'hidden', 
                                    boxShadow: '0 20px 40px rgba(0,0,0,0.3)',
                                    cursor: 'zoom-in'
                                }}>
                                    <img 
                                        src={photo} 
                                        alt={`${item.name} - view ${i + 1}`} 
                                        style={{ height: '700px', width: 'auto', display: 'block' }} 
                                    />
                                </Box>
                            </SwiperSlide>
                        ))}
                        <div className="swiper-button-prev" />
                        <div className="swiper-button-next" />
                    </Swiper>
                </Grid>

                <Grid item xs={12} md={5}>
                    <Box sx={{ position: 'sticky', top: '120px' }}>
                        <Typography variant="overline" sx={{ color: 'primary.main', fontWeight: 700, letterSpacing: '0.2em' }}>
                            Premium Essentials
                        </Typography>
                        <Typography variant="h2" sx={{ mt: 1, mb: 2, fontWeight: 800 }}>
                            {item.name}
                        </Typography>

                        <Stack direction="row" spacing={2} alignItems="baseline" sx={{ mb: 4 }}>
                            <Typography variant="h4" sx={{ fontWeight: 800, color: 'primary.main' }}>
                                {item.currentPrice} ₴
                            </Typography>
                            {item.firstPrice && (
                                <Typography variant="h6" sx={{ textDecoration: 'line-through', color: 'text.secondary', opacity: 0.6 }}>
                                    {item.firstPrice} ₴
                                </Typography>
                            )}
                        </Stack>

                        <Box sx={{ mb: 4 }}>
                            <Typography variant="subtitle2" sx={{ mb: 2, fontWeight: 700, textTransform: 'uppercase' }}>
                                Select Size
                            </Typography>
                            <ToggleButtonGroup
                                value={alignmentSize}
                                exclusive
                                onChange={handleAlignmentSize}
                                sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}
                            >
                                {item.sizes.map((size) => (
                                    <ToggleButton 
                                        key={size} 
                                        value={size} 
                                        sx={{ 
                                            width: '60px', 
                                            height: '50px', 
                                            borderRadius: '12px !important',
                                            border: '1px solid rgba(255,255,255,0.1) !important',
                                            fontWeight: 700,
                                        }}
                                    >
                                        {size}
                                    </ToggleButton>
                                ))}
                            </ToggleButtonGroup>
                        </Box>

                        {item.colors.length > 1 && (
                            <Box sx={{ mb: 4 }}>
                                <Typography variant="subtitle2" sx={{ mb: 2, fontWeight: 700, textTransform: 'uppercase' }}>
                                    Select Color
                                </Typography>
                                <ToggleButtonGroup
                                    value={alignmentColor}
                                    exclusive
                                    onChange={handleAlignmentColor}
                                    sx={{ gap: 2 }}
                                >
                                    {item.colors.map((color) => (
                                        <ToggleButton 
                                            key={color} 
                                            value={color} 
                                            sx={{ 
                                                p: 0.5, 
                                                borderRadius: '50% !important', 
                                                border: alignmentColor === color ? '2px solid #D4AF37 !important' : '2px solid transparent !important'
                                            }}
                                        >
                                            <Box sx={{ width: '28px', height: '28px', backgroundColor: color, borderRadius: '50%' }} />
                                        </ToggleButton>
                                    ))}
                                </ToggleButtonGroup>
                            </Box>
                        )}

                        <Stack direction="row" spacing={2} sx={{ mb: 6 }}>
                            <Button 
                                fullWidth
                                variant="contained"
                                size="large"
                                onClick={() => setOrder({
                                    poster: item.photos[0],
                                    id: item.id,
                                    name: item.name,
                                    price: item.currentPrice,
                                    color: alignmentColor,
                                    size: alignmentSize
                                })}
                                sx={{ 
                                    height: '64px', 
                                    fontSize: '1.1rem', 
                                    fontWeight: 700,
                                    borderRadius: '16px'
                                }}
                            >
                                Add to Bag
                            </Button>
                            <IconButton 
                                onClick={() => setWishList({
                                    poster: item.photos[0],
                                    id: item.id,
                                    name: item.name,
                                    price: item.currentPrice,
                                })}
                                sx={{ 
                                    width: '64px', 
                                    height: '64px', 
                                    borderRadius: '16px',
                                    border: '1px solid rgba(255,255,255,0.1)',
                                    color: isInWishList ? 'primary.main' : 'white'
                                }}
                            >
                                {isInWishList ? <FavoriteRoundedIcon /> : <FavoriteBorderRoundedIcon />}
                            </IconButton>
                        </Stack>

                        <Box sx={{ mt: 6 }}>
                            <Typography variant="h6" sx={{ mb: 3, fontWeight: 800, textTransform: 'uppercase' }}>
                                Product Details
                            </Typography>
                            {item.attributes.map((attribute) => (
                                putPropertyAndValue(attribute[0], attribute[1])
                            ))}
                            <Typography variant="body1" sx={{ mt: 3, color: 'text.secondary', lineHeight: 1.8 }}>
                                {item.description}
                            </Typography>
                        </Box>
                    </Box>
                </Grid>
            </Grid>

            {similarGoods()}

            <Modal
                open={isphotoOpen}
                onClose={() => setphotoOpen(false)}
                sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', p: 4 }}
            >
                <Box 
                    onClick={() => setphotoOpen(false)}
                    sx={{ maxWidth: '90vw', maxHeight: '90vh', outline: 'none', cursor: 'zoom-out' }}
                >
                    <img src={CurrentPhoto} alt="Product Zoom" style={{ width: '100%', height: '100%', objectFit: 'contain' }} />
                </Box>
            </Modal>
        </Box>
    )
}

export default Item;
